+        },
+      ],
+      onClientToolCall,
+      { agentId: "main", sessionKey: "main" },
+    );
+
+    await tool.execute("client-call-1", { value: "ok" }, undefined, undefined, undefined);
+
+    expect(onClientToolCall).toHaveBeenCalledWith("client_tool", {
+      value: "ok",
+      extra: true,
+    });
+  });
